components.css:
.ds-btn{display:inline-flex;align-items:center;gap:6px;padding:8px 14px;border-radius:9px;border:1px solid var(--border-strong);background:var(--bg-card);color:var(--text);font:inherit;cursor:pointer;white-space:nowrap;transition:border-color .15s,background .15s}
.ds-btn:hover:not(:disabled){border-color:var(--accent-line)}
.ds-btn:disabled{opacity:.55;cursor:default}
.ds-btn-primary{background:var(--accent-dim);border-color:var(--accent-line);color:var(--accent)}
.ds-btn-primary:hover:not(:disabled){background:rgba(47,214,164,.2)}
.ds-btn-ghost{background:transparent;border-color:transparent;color:var(--text-dim)}
.ds-btn-ghost:hover:not(:disabled){color:var(--text);border-color:var(--border-strong)}
.ds-btn-danger{color:var(--red);border-color:rgba(242,109,109,.4)}
.ds-btn-sm{padding:5px 11px;font-size:12.5px;border-radius:8px}
.ds-icon-btn{width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;border-radius:7px;border:1px solid var(--border-strong);background:transparent;color:var(--text-dim);line-height:1;cursor:pointer}
.ds-icon-btn:hover{color:var(--accent);border-color:var(--accent-line)}
.ds-spinner{display:inline-block;width:11px;height:11px;border-radius:50%;border:2px solid currentColor;border-top-color:transparent;animation:ds-spin .8s linear infinite}
@keyframes ds-spin{to{transform:rotate(360deg)}}
.ds-btn:focus-visible,.ds-icon-btn:focus-visible{outline:2px solid var(--accent);outline-offset:2px;border-color:var(--accent)}

.ds-nav-list{display:flex;flex-direction:column;gap:2px;padding:4px 10px 8px;border-bottom:1px solid var(--border)}
.ds-nav-item{display:flex;align-items:center;gap:11px;width:100%;text-align:left;padding:8px 10px;border-radius:10px;border:1px solid transparent;background:transparent;color:var(--text-dim);font-size:13.5px;font-family:inherit;cursor:pointer}
.ds-nav-item:not(:disabled):hover{background:var(--bg-card);color:var(--text)}
.ds-nav-item.ds-active{background:var(--accent-dim);border-color:var(--accent-line);color:var(--text)}
.ds-nav-item.ds-active .ds-nav-glyph{color:var(--accent)}
.ds-nav-item:disabled{opacity:.5;cursor:default}
.ds-nav-glyph{width:18px;text-align:center;color:var(--text-mute);font-size:15px;flex:none}
.ds-nav-label{flex:1}
.ds-nav-soon{font-size:9.5px;letter-spacing:.08em;text-transform:uppercase;padding:1px 6px;border-radius:999px;background:var(--bg-card-2);color:var(--text-mute);border:1px solid var(--border)}
.ds-room-item{display:flex;align-items:center;gap:10px;width:100%;text-align:left;padding:9px 10px;border-radius:11px;border:1px solid transparent;background:transparent;font-family:inherit;cursor:pointer;color:var(--text)}
.ds-room-item:hover{background:var(--bg-card)}
.ds-room-item.ds-selected{background:var(--accent-dim);border-color:var(--accent-line)}
.ds-room-hex{width:34px;height:34px;display:inline-flex;align-items:center;justify-content:center;border-radius:9px;font-size:18px;flex:none}
.ds-room-info{display:flex;flex-direction:column;min-width:0;flex:1}
.ds-room-name{font-weight:600;font-size:13.5px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.ds-room-meta{font-size:11.5px;color:var(--text-mute)}

.ds-panel-tabs{display:flex;gap:4px;padding:12px 14px 0;border-bottom:1px solid var(--border)}
.ds-panel-tabs button{background:none;border:none;border-bottom:2px solid transparent;padding:8px 12px 10px;color:var(--text-dim);font-weight:600;font-size:13.5px;font-family:inherit;cursor:pointer}
.ds-panel-tabs button:hover{color:var(--text)}
.ds-panel-tabs button.ds-active{color:var(--text);border-bottom-color:var(--accent)}
.ds-count{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;margin-left:5px;border-radius:999px;font-size:10.5px;background:var(--bg-card-2);border:1px solid var(--border-strong);color:var(--text-dim)}
